external_knowledge:
- "Traffic lights dancing slower than a minute" refers to traffic signals with a cycle time greater than 60 seconds;
- "The identities" refers to the names and unique identifiers of the intersections;
- "Their unique codes" refers to the unique identifiers of the traffic signals;
- "The time they spend in their rhythm" is the cycle time of the traffic signals;
- "Their current stance" is the current status of the traffic signals;
- "The flow and speed of vehicles passing through" are the traffic volume and speed;
- "When these details were last noted" is the time stamp of the data.

sql:
SELECT signal_id, type, configuration
FROM traffic_signals
WHERE type = '3-phase';

SELECT intersection_id, name, location, description
FROM intersections
ORDER BY name;

SELECT status, COUNT(*) as Number_of_Signals
FROM traffic_signals
GROUP BY status;

SELECT COUNT(*) as Total_Intersections
FROM intersections
WHERE neighborhood = 'Downtown';

SELECT COUNT(DISTINCT intersection_id) AS num_intersections
FROM traffic_volumes
WHERE total_flow > (
    SELECT AVG(total_flow) 
    FROM traffic_volumes
);
